window.__QUIZ_DATA__=[{"id":"theory>Geography>2011>Theory 1>1>a","subject":"Geography","year":"2011","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map extracted on the scale of 1:50,000 and answer the following questions:","images":[],"marking_scheme":"Given; Scale = 1:50,000   An outline of the map   Length of original map = 36.cm  Breadth of original map = 36.6cm    ForNewOutline;length=36.6cm3=12.2cm    Breadth=36.6cm3cm=12.2cm    \u2234 Original scale = 1:50,000   \u2234 New scale = 1:150,000","marks":"5","difficulty":"3"},{"id":"theory>Geography>2011>Theory 1>1>b","subject":"Geography","year":"2011","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"On the new outline, insert the name:  (i) Otta settlement; (ii) a 250 ft. contour line in the easter part;   (iii) the full length of Iju stream and show its direction of flow with an arrow.","images":[],"marking_scheme":"On the new outline, we name the otta settlement a 250ft contour line in the eastern part and the full length of Iju stream.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2011>Theory 1>1>c","subject":"Geography","year":"2011","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"State three functions of Otta settlement","images":[],"marking_scheme":"- It serves as a centre of education   - It serves health functions  - It serves judicial functions by the presence of a court","marks":"5","difficulty":"1"},{"id":"theory>Geography>2011>Theory 1>1>d","subject":"Geography","year":"2011","type":"Theory","sub_label":"d","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : POPULATION","question":"State two occupations of the inhabitants of Idiroko and give reasons for you answer.","images":[],"marking_scheme":"- Teaching; as shown by the presence of schools   - Trading; as shown by the presence of market","marks":"5","difficulty":"2"},{"id":"theory>Geography>2011>Theory 1>2>a>i","subject":"Geography","year":"2011","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : PRINCIPLES OF ELEMENTARY SURVEYING","question":"Describe each of the following instruments used in chain surveying   - Ranging pole","images":[],"marking_scheme":"This is a sharp pointed circular/round light metal or wood ranging from 2 - 3 metres which is driven into the ground during chain surveying. It is usually painted in alternating colours of black, white and red or black and white or red and white.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2011>Theory 1>2>a>ii","subject":"Geography","year":"2011","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : PRINCIPLES OF ELEMENTARY SURVEYING","question":"Describe each of the following instruments used in chain surveying   - Arrows","images":[],"marking_scheme":"This is a sharp pointed steel rod measuring about 38cm 15inches in height. It is coloured for easy spotting from a distance.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2011>Theory 1>2>b","subject":"Geography","year":"2011","type":"Theory","sub_label":"b","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : PRINCIPLES OF ELEMENTARY SURVEYING","question":"With the aid of a diagram, show how you would overcome an uncompleted building which poses an obstacle to chaining.","images":["data:image/png;base64,"],"marking_scheme":"(i) Select two points A and B on  chain line close to the uncompleted building.   (ii) Erect two equal and perpendicular lines each at each A and B to extend beyond the uncompleted building.   (iii) Mark the two ends C and D   (iv) Produce/CD/beyond the uncompleted building   (v) Mark two points E and F. From the points E and F, drop two equal and parallel perpendicular lines to the point G and H.   (vi) |GE|, and |HP|  (vii) G and H are in line with the chain line  (viii) Measure |DE| and record the distance   (ix) Measure line |BG| is equal and parallel to |DE|. Then continue the measurement from G.","marks":"10","difficulty":"3"},{"id":"theory>Geography>2011>Theory 1>3>a>i","subject":"Geography","year":"2011","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Name any two types of rainfall","images":[],"marking_scheme":"\u2192 Conventional rainfall   \u2192 Orographic/Relief rainfall","marks":"5","difficulty":"1"},{"id":"theory>Geography>2011>Theory 1>3>a>ii","subject":"Geography","year":"2011","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"State the region where each of the two types of rainfall named in (a)(i) above is prevalent","images":[],"marking_scheme":"r \u2192 Relief rainfall occurs in highland or mountainous regions","marks":"5","difficulty":"2"},{"id":"theory>Geography>2011>Theory 1>3>b>i","subject":"Geography","year":"2011","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Write explanatory notes on the formation of the formation of the two types of rainfall named in a (a)(i) above","images":[],"marking_scheme":"- Conventional rainfall: Is formed from the vapour that rises and expands after the earth surface is heated. The moisure is carried by convention currents and condense into the cumulonimbus cloud Further cooling results in formation of water droplets which fall back as torrential downpour which is accompanied by thunder and lighting. Convectional rainfall is common in temperate region especially in the summer.","marks":"5","difficulty":"3"},{"id":"theory>Geography>2011>Theory 1>3>b>ii","subject":"Geography","year":"2011","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Write explanatory notes on the formation of the formation of the two types of rainfall named in a (a)(i) above","images":[],"marking_scheme":"Orographic rainfall: Is formed when moist winds which are blown horizontally come into contact with a highland, thereby forcing the ascension of the moisure-laden wind. Further rising leads to expanding and cooling after which the wind gas cools and water vapour condenses forming rainfall on the wind-ward side of the mountain.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2011>Theory 1>4>a>i","subject":"Geography","year":"2011","type":"Theory","sub_label":"i","group":"FINAL","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Use the table below to answer the questions that follow  Months J F M A M J J A S O N DRainfall (mm) 10 80 20 18 5 50 40 40 90 20 50 40    Calculate the:  - annual rainfall","images":[],"marking_scheme":"Annual rainfall from January to December = Total Annual Rainfall = 10+80+20+18+5+50+40+40+90+20+50+40 = 463mm","marks":"5","difficulty":"1"},{"id":"theory>Geography>2011>Theory 1>4>a>ii","subject":"Geography","year":"2011","type":"Theory","sub_label":"ii","group":"FINAL","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Use the table below to answer the questions that follow  Months J F M A M J J A S O N DRainfall (mm) 10 80 20 18 5 50 40 40 90 20 50 40mean annual rainfall","images":[],"marking_scheme":"MeanAnnualRainfall=Tot. Annual Rainfall12    =463mm12=38.58mm","marks":"5","difficulty":"1"},{"id":"theory>Geography>2011>Theory 1>4>b>i","subject":"Geography","year":"2011","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Name the instrument used in measuring the following weather elements:    - pressure","images":[],"marking_scheme":"- Barometer","marks":"2","difficulty":"1"},{"id":"theory>Geography>2011>Theory 1>4>b>ii","subject":"Geography","year":"2011","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Name the instrument used in measuring the following weather elements:sunshine","images":[],"marking_scheme":"- Sundial/sunshine recorder","marks":"1","difficulty":"1"},{"id":"theory>Geography>2011>Theory 1>4>b>iii","subject":"Geography","year":"2011","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Name the instrument used in measuring the following weather elements:- rainfall","images":[],"marking_scheme":"- Rainguage","marks":"1","difficulty":"1"},{"id":"theory>Geography>2011>Theory 1>4>b>iv","subject":"Geography","year":"2011","type":"Theory","sub_label":"iv","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Name the instrument used in measuring the following weather elements:- temperature","images":[],"marking_scheme":"- Thermometer","marks":"1","difficulty":"1"},{"id":"theory>Geography>2011>Theory 1>4>c","subject":"Geography","year":"2011","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Describe four effects of climate on agriculture","images":[],"marking_scheme":"- It supports the growth of grain crops(rice, millet, etc) during period of high temperature and less rainfall.   - Wind aids pollination, winnowing and seeds dispersal   - In the equational climate region with high temperature and rainfall, root crop's survive better.  - Sunshine is needed by plants for photosynthesis","marks":"5","difficulty":"2"},{"id":"theory>Geography>2011>Theory 1>5>a","subject":"Geography","year":"2011","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Explain the process of wind erosion","images":[],"marking_scheme":"Process of wind Erosion.    (i) Abrasion:  This is the sand blasting of rock surface by wind. The wind hurls hard quartz grains against the rocks, smoothening and polishing it into a hard uniform rock.      (ii) Deflation:  This occurs when the wind forces acts on the earth surface lifting and blowing away unconsolidated materials by the wind.      (iii) Attrition:  The rock particles are reduced in size since they rub against one another in collision. Sand particles formed are carried away sattation, gravel and small stones are lifted or moved by traction and fine materials are carried away in suspension.","marks":"10","difficulty":"2"},{"id":"theory>Geography>2011>Theory 1>5>b","subject":"Geography","year":"2011","type":"Theory","sub_label":"b","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"With the aid of a diagram, describe the features of a barchan dune.","images":["data:image/png;base64,"],"marking_scheme":"Barchan Dune   This is a crescent-shaped sand dume which occurs either indivdually or in groups. It has two horns which always point in the wind direction. It also has a gentle and convex slope at the wind-ward side while the leeward side is steepy concave. Examples include; Sahara and Turkestan desert.","marks":"10","difficulty":"3"},{"id":"theory>Geography>2011>Theory 1>6>a>i","subject":"Geography","year":"2011","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Write explanatory note on the following:    springs;","images":[],"marking_scheme":"They are found when there is an easy water outlet from the ground. It can also be formed when the water table meets the surface of the earth where impermeable rocks are overlain by limestone rocks. Springs develop along the junctions of the two rocks. Examples includes; New Zealand California, Italy, Nigeria(Ikogosi), etc.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2011>Theory 1>6>a>ii","subject":"Geography","year":"2011","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Write explanatory note on the following:  caverns","images":[],"marking_scheme":"This is an underground feature of the limestone region which links to the earth surface by shallow holes and is formed by the dissolution of limestone beneath the earth surface. With further water penetration, some water droplets are left on the roof of the cave which accumulate from stalagmites. The two then meet to form the 'Calcite pillar.' E.g. Kentucky Cave (USA), carisbad cave (New Mexico, USA), etc.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2011>Theory 1>6>b","subject":"Geography","year":"2011","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Highlight four ways in which limestone is important to man.","images":[],"marking_scheme":"- It provides tourism - attracting features.   - It serves as a source of raw materials for cement industries   - It also serves as a source of revenue generation   - It is used for construction","marks":"10","difficulty":"2"},{"id":"theory>Geography>2011>Theory 1>7>a","subject":"Geography","year":"2011","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL PROBLEMS/ HAZARDS","question":"Describe any three causes of air pollution","images":[],"marking_scheme":"- ChloroFluoro carbons (CFCs) produced from sprays and cooling systems  - Smoke emission from domestic and Industrial sources   - Volcanic Eruptions","marks":"10","difficulty":"3"},{"id":"theory>Geography>2011>Theory 1>7>b","subject":"Geography","year":"2011","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL PROBLEMS/ HAZARDS","question":"Outline three major effects of air pollution.","images":[],"marking_scheme":"- Destruction of living organisms and the soil   - Formation of acid rain which com materials and burns plants  - Destruction and depletion of the ozone layer","marks":"5","difficulty":"3"},{"id":"theory>Geography>2011>Theory 1>7>c","subject":"Geography","year":"2011","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL CONSERVATION","question":"Suggest two ways of controlling air pollution","images":[],"marking_scheme":"- Government should legislate on air pollution   - The public should be educated on waste disposal.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2011>Theory 1>8>a>i","subject":"Geography","year":"2011","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Name the types of power derived from each of the following sources:    - water;","images":[],"marking_scheme":"- Hydro-electric power","marks":"3","difficulty":"1"},{"id":"theory>Geography>2011>Theory 1>8>a>ii","subject":"Geography","year":"2011","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Name the types of power derived from each of the following sources: - coal;","images":[],"marking_scheme":"- Thermal energy/power","marks":"3","difficulty":"1"},{"id":"theory>Geography>2011>Theory 1>8>a>iii","subject":"Geography","year":"2011","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Name the types of power derived from each of the following sources: - natural gas;","images":[],"marking_scheme":"- Thermal energy/power","marks":"3","difficulty":"1"},{"id":"theory>Geography>2011>Theory 1>8>a>iv","subject":"Geography","year":"2011","type":"Theory","sub_label":"iv","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Name the types of power derived from each of the following sources: - the sun","images":[],"marking_scheme":"- Solar energy/power","marks":"3","difficulty":"1"},{"id":"theory>Geography>2011>Theory 1>8>b>i","subject":"Geography","year":"2011","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL RESOURCES","question":"Write explanatory notes on the types of power obtained from water and sun under the following headings;    - specific places of production","images":[],"marking_scheme":"(i) Hydro-electric Power   It is specifically produced in kainji, Nigeria, Akosombo (Ghana), Shasta (USA), Bumbuna and Dodo (Siera Leone), etc.","marks":"4","difficulty":"3"},{"id":"theory>Geography>2011>Theory 1>8>b>ii","subject":"Geography","year":"2011","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL RESOURCES","question":"Write explanatory notes on the types of power obtained from water and sun under the following headings; - method of production","images":[],"marking_scheme":"- It is produced by the construction of a dam to raise the water level in order to create a reservoir. The flow of the water at that height becomes swift and the water is channelled through the penstocks to turn the turbine connected to generator which produces the power.","marks":"3","difficulty":"3"},{"id":"theory>Geography>2011>Theory 1>8>b>iii","subject":"Geography","year":"2011","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL RESOURCES","question":"Write explanatory notes on the types of power obtained from water and sun under the following headings; - uses","images":[],"marking_scheme":"It is used for domestic and industrial purposes e.g. Lighting, Cooking, Ironing, Manufacturing, minerals Smelting, etc.","marks":"2","difficulty":"2"},{"id":"theory>Geography>2011>Theory 2>1>a>i","subject":"Geography","year":"2011","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Define the term migration","images":[],"marking_scheme":"- Migration can be defined as the movement of people from one location to another to settle either temporarily or permanently","marks":"5","difficulty":"1"},{"id":"theory>Geography>2011>Theory 2>1>a>ii","subject":"Geography","year":"2011","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Name four types of migration in Africa","images":[],"marking_scheme":"- Rural - Urban migration   - Rural - rural migration   - Seasonal migration   - Urban-rural migration","marks":"5","difficulty":"2"},{"id":"theory>Geography>2011>Theory 2>1>b","subject":"Geography","year":"2011","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Outline any four causes of migration can be reduced in Africa.","images":[],"marking_scheme":"- Famine   - Employment opportunities  - Unfavourable economic conditions   - Natural disasters","marks":"5","difficulty":"2"},{"id":"theory>Geography>2011>Theory 2>1>c","subject":"Geography","year":"2011","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Suggest any three ways by which migration can be reduced in Africa.","images":[],"marking_scheme":"- Good governance   - Initiation of programmes for poverty alleviation  - Establishment of social amenities and infrastructures in rural areas","marks":"5","difficulty":"2"},{"id":"theory>Geography>2011>Theory 2>2>a>i","subject":"Geography","year":"2011","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Write notes on:    - dispersed settlement;","images":[],"marking_scheme":"This is made up of several scattered houses of which one house may be bout 1km from the next. It is usually associated with rural communities and farmlands are usually behind buildings.","marks":"5","difficulty":"1"},{"id":"theory>Geography>2011>Theory 2>2>a>ii","subject":"Geography","year":"2011","type":"Theory","sub_label":"ii","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Write notes on:linear settlement","images":[],"marking_scheme":"This is a farm of settlement that stretches along physical features such as lakes, elongated encarpment, etc. It could either be straight or curled lines of communication along railways, roads, etc. It is rural in nature and may be on the outskirts of towns. Gardens exist behind the house while farm are behind the gardens.","marks":"5","difficulty":"1"},{"id":"theory>Geography>2011>Theory 2>2>b","subject":"Geography","year":"2011","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Explain any four factors that favour the location of settlements.","images":[],"marking_scheme":"- Locations where minerals exist e.g. Jos in Nigeria, Ndola, Kolwesi and Likasi in Central Africa, and Johannesburg in South Africa.   - Locations where there is an indentation on the coast line E.g Riode Janeiro in Branzil, Lagos in Nigeria, Tokyo in Japan, Freetown in Sierra Leone and Buenos Aires in Argentina   - Locations where routesways meet i.e Nodal towns E.g Chicago in the united states of America, Singapore in Malaysia and Aba in Nigeria.  - Locations at the bse of hills E.g Wase village in Benue Valley (Nigeria), Edinburgh in Scotland and Durbah in England.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2011>Theory 2>2>c","subject":"Geography","year":"2011","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Outline any four functions of an urban settlement","images":[],"marking_scheme":"- Provision of employment opportunities   - Provision of social services and higher order services   - Presence of active and functional educational centres","marks":"5","difficulty":"2"},{"id":"theory>Geography>2011>Theory 2>3>a","subject":"Geography","year":"2011","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Highlight five advantages that air transport has over other means of transportation","images":[],"marking_scheme":"- It covers longer distances in shorter time duration than other means of transportation.  - It makes use of direct routes   - It is relatively more secured   - It can be effectively used in cases of emergency   - It routes do not require maintenance","marks":"10","difficulty":"2"},{"id":"theory>Geography>2011>Theory 2>3>b","subject":"Geography","year":"2011","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Explain five problems limiting air transportation in your country.","images":[],"marking_scheme":"- Low level of technology   - High cost of maintenance of aircrafts and aviation fuel.   - Low percentage due to low income since it is more expensive to travel by air than other means of transportation.   - Limited routes in various parts of the country since aircrafts/fields are needed for most aircrafts   - Weather hazards","marks":"10","difficulty":"3"},{"id":"theory>Geography>2011>Theory 2>4>a","subject":"Geography","year":"2011","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Draw a sketch map of Nigeria. On the map, mark and name:   (i) latitudes 5oN, 13oN and longitude 8oE; (ii) one area with rainfall of about 600 mm;   (iii) one area with rainfall between 2000 mm and 3050 mm; (iv) One town in each of the areas in (ii) and (iii) above","images":["data:image/png;base64,"],"marking_scheme":"","marks":"10","difficulty":"3"},{"id":"theory>Geography>2011>Theory 2>4>b","subject":"Geography","year":"2011","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Describe the rainfall pattern in Nigeria.","images":[],"marking_scheme":"In Nigeria, rainfall is not uniformly distributed. High altitudes create islands of higher rainfalls of between 1500 - 2000mm per year, while coastal areas receive over 3000mm of rainfall within 8 - 10 moths. The north receives less than 250mm of rainfall over about 3 months. There is also a double maxima rainfall regime in the Southern Nigeria in June and October. There are two main seasons, namely; The rainy and dry season. There is also a little dry season in the month of August which is popularly known as the August break. The onset of rainy season is usually heralded by lightning and thunderstorms which can later be succeeded by rainfalls heavy enough to cause destructive floods. The heaviest rainfall in Nigeria occurs in the South West and South East.","marks":"10","difficulty":"2"},{"id":"theory>Geography>2011>Theory 2>5>a","subject":"Geography","year":"2011","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Draw a sketch map of Nigeria. On the map show and name:  (i) the North Central Highlands; (ii) the rivers Niger and Benue","images":["data:image/png;base64,"],"marking_scheme":"","marks":"5","difficulty":"2"},{"id":"theory>Geography>2011>Theory 2>5>b","subject":"Geography","year":"2011","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Name two export crops and four food crops of the North Central Highlands.","images":[],"marking_scheme":"(i) Export Crops   - cotton   - Groundnut   (ii) Food Crops   - Maize   - Rice   - Tomatoes   - Yams","marks":"5","difficulty":"1"},{"id":"theory>Geography>2011>Theory 2>5>c>i","subject":"Geography","year":"2011","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Describe the North Central Highlands under the following headings:    Jos Plateau, Oban Hills and Mandara Mountains;","images":[],"marking_scheme":"The major agricultural activities that people deal with in the Northern Central Highlands include, mixed cropping animal rearing, poultry, nomadic herding, irrigation farming, fishing, etc.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2011>Theory 2>5>c>ii","subject":"Geography","year":"2011","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ISSUES ON DEVELOPMENT AND ENVIRONMENTAL CONCERNS","question":"Describe the North Central Highlands under the following headings:  problems of development","images":[],"marking_scheme":"- It is majorly practised by subsistence   - There is high incidence of diseases   - Problems of pests   - Labour shortage because of urban rural migration   - High rate of evapo-transpiration","marks":"5","difficulty":"3"},{"id":"theory>Geography>2011>Theory 2>6>a","subject":"Geography","year":"2011","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Draw a sketch map of Nigeria. On the map, locate the name:  (i) Jos Plateau, Oban Hills and Mandara Mountains;   (ii) Rivers Ogun and Gongola.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"10","difficulty":"2"},{"id":"theory>Geography>2011>Theory 2>6>b","subject":"Geography","year":"2011","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : NIGERIA ON BROAD OUTLINE","question":"Describe the location and size of Nigeria.","images":[],"marking_scheme":"- It is located in a fairly central position in Africa   - It extends from latitude 4oN and 14oN with latitudinal extent of 100   - It also extends from longitude 30E and 150E with longitudinal extent of 120   - It is bordered by Cameroon Republic to the east, by Chad Republic to the North-East, by Benin Republic to the west, by Atlantic ocean to the south. - It marks the eastern border of West Africa    It is approximately 923,76859km in land area. Its widest point East-West along latitude 12oN is approximately 1,100km wide. It occupies 1/7th of the total mainland of West Africa. It is also about four times the size of Ghna, thirteen times Sierraleone, eighty six times Gambia. It is the fourth largest country in West Africa and also the most populous country in Africa.","marks":"5","difficulty":"1"},{"id":"theory>Geography>2011>Theory 2>6>c","subject":"Geography","year":"2011","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Highlight three economic importance of highlands to the economy of Nigeria.","images":[],"marking_scheme":"- Agricultural activities  - Source of mineral resources   - Provision of Tourist Centres","marks":"5","difficulty":"2"},{"id":"theory>Geography>2011>Theory 2>7>a","subject":"Geography","year":"2011","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Draw an outline map of Africa. On the map, show and name:  (i) the Kanji Dam; (ii) Aswan Dam; (iii) Drakensberg Mountains (iv) the Atlas Mountains.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"10","difficulty":"3"},{"id":"theory>Geography>2011>Theory 2>7>b","subject":"Geography","year":"2011","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Outline five importance of hydroelectric power to the economic of African countries","images":[],"marking_scheme":"- Provision of job opportunities   - Generation of revenue for government   - Generation of Power for Industrial and domestic uses   - Generation of foreign exchange   - Provision of attachment for workers","marks":"10","difficulty":"2"},{"id":"theory>Geography>2011>Theory 2>8>a","subject":"Geography","year":"2011","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"Draw a sketch map of Africa. On On it show and name:  (i) Cameroun Highlands; (ii) Fouta Djallon Highlands;   (iii) One important river that takes its source from any of the highlands named in (a)(i) and (ii) above.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"10","difficulty":"3"},{"id":"theory>Geography>2011>Theory 2>8>b","subject":"Geography","year":"2011","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Highlight four ways in which rivers are important to the economy of Africa.","images":[],"marking_scheme":"- They serve as a generator for H.E.P (Hydro Electric Power)  - They serve domestic domestic uses   - For recreation and tourism   - They serve as a medium of transportation and carriage.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2011>Theory 2>8>c","subject":"Geography","year":"2011","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Outline three problems limiting the use of African rivers.","images":[],"marking_scheme":"- Presence of debris and floating vegetation   - Inadequate capital to finance the construction of ports   - Fluctuation in the volume of water","marks":"5","difficulty":"2"},{"id":"theory>Geography>2011>Theory 2>9>a","subject":"Geography","year":"2011","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"Identify any four factors that favour lumbering in Democratic Republic of Congo.","images":[],"marking_scheme":"- Availability of foreign capital   - Effective sawmill industries are available to process the raw materials   - Presence of forest vegetation belt   - Availability of markets for the sale of timber both at home and abroad.","marks":"10","difficulty":"2"},{"id":"theory>Geography>2011>Theory 2>9>b","subject":"Geography","year":"2011","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"Explain any four problems of lumbering in Democratic Republic of Congo.","images":[],"marking_scheme":"- Swampy nature of ground makes the timber muddy and almost unpassable  - Hardness of woods prevent them from floating easily on water   - Mass depletion of Forest Resources  - The interiority of the lumbering zones makes it harder to transport the timber for export.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2011>Theory 2>9>c","subject":"Geography","year":"2011","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"Outline two ways in which any of the problems in (b) above cold be solved.","images":[],"marking_scheme":"- Wide tracks (timber) should be cleared for easy evacuation of already felled logs  - Legislation should be made against illegal felling of trees","marks":"5","difficulty":"1"}];